def _fail_and_log(step_name: str, e: Exception):
    global error_message

    try:
        error_message = f"[{step_name}] {type(e).__name__}: {str(e)}"[:800]
    except Exception as format_error:
        error_message = (
            f"[{step_name}] Failed to format original exception: "
            f"{type(format_error).__name__}: {str(format_error)}"
        )[:800]

    try:
        logError(error_message)
    except Exception as log_error:
        print(f"Primary logging failed: {log_error}")
        print(error_message)

    try:
        telemetry_fn = globals().get("_log_telemetry")
        if callable(telemetry_fn):
            telemetry_fn("Failed", error_message, step_name)
        else:
            print("Telemetry function '_log_telemetry' is not yet defined. Skipping telemetry.")
    except Exception as telemetry_error:
        print(f"Telemetry logging failed: {telemetry_error}")

    raise e

def run_step(step_name: str, fn):
    try:
        return fn()
    except Exception as e:
        _fail_and_log(step_name, e)

def read_raw_messages(source_path: str) -> DataFrame:
    """
    Reads all service bus messages stored as JSON files under the entity raw path.
    Returns an empty DataFrame (with schema if provided) when no files exist.
    """
    reader = (
        spark.read
        .option("multiline", "true")
        .option("recursiveFileLookup", "true")
    )
    if spark_schema:
        reader = reader.schema(spark_schema)

    try:
        df = reader.json(source_path)
    except Exception as e:
        logInfo(f"No files found or error reading from {source_path}: {e}")
        return (
            spark.createDataFrame([], schema=spark_schema)
            if spark_schema
            else spark.createDataFrame([], StructType())
        )

    df = (
        df.withColumn("expected_from", F.current_timestamp())
          .withColumn("expected_to", F.expr("current_timestamp() + INTERVAL 1 DAY"))
          .withColumn("ingested_datetime", F.to_timestamp(watermark_column))
          .withColumn("input_file", F.input_file_name())
    )

    logInfo(f"Read {df.count()} rows from {source_path}")
    return df

last_ingest_time = None
try:
    wm_row = spark.sql(
        f"SELECT MAX(last_ingest_time) AS wm_ts "
        f"FROM odw_meta_db.service_bus_watermarks "
        f"WHERE entity = '{entity_name}' AND source = 'service-bus'"
    ).collect()
    if wm_row and wm_row[0][0]:
        last_ingest_time = str(wm_row[0][0])
        logInfo(f"Watermark found: last_ingest_time={last_ingest_time}")
    else:
        logInfo(f"No watermark found for {entity_name} — all RAW records will be processed")
except Exception as e:
    logInfo(f"Watermark table not accessible, processing all RAW records: {str(e)[:200]}")

if last_ingest_time:
    df = df.filter(
        F.col(watermark_column).cast("timestamp") > F.lit(last_ingest_time).cast("timestamp")
    )
    logInfo(f"Watermark filter applied ({watermark_column} > {last_ingest_time})")

if df.count() == 0:
    logInfo("No new records after watermark filter — exiting gracefully.")
    mssparkutils.notebook.exit(json.dumps({
        "hasNewData": False,
        "max_message_enqueued_time_utc": None,
        "table_details": [{"insert_count": 0, "update_count": 0, "delete_count": 0, "total_exec_time": 0, "error_message": None}],
    }))

try:
    max_ts_row = df.agg({watermark_column: "max"}).collect()
    max_message_enqueued_time_utc = str(max_ts_row[0][0]) if max_ts_row and max_ts_row[0][0] else None
except Exception as _mts_err:
    logError(f"Failed to compute max watermark value: {str(_mts_err)[:200]}")

def step_validate_rows_appended():
    if not test_rows_appended(
        new_table_row_count=new_table_row_count,
        expected_row_count=expected_new_count
    ):
        logError(
            f"Row count mismatch after append to {target_table}: "
            f"expected={expected_new_count}, actual={new_table_row_count}"
        )
        return False
    logInfo("Rows appended successfully")
    return True

rows_valid = run_step("validate rows appended", step_validate_rows_appended)
